// Module scope: runs ONCE per execution environment (during Init).
// Reuse expensive clients across warm invocations.
import { DynamoDBClient } from '@aws-sdk/client-dynamodb';
import { DynamoDBDocumentClient, PutCommand } from '@aws-sdk/lib-dynamodb';

const ddb = DynamoDBDocumentClient.from(new DynamoDBClient({}));
const TABLE = process.env.TABLE_NAME!;

// Handler scope: runs ONCE PER INVOCATION on a warm environment.
export const handler = async (event: { id: string; body: string }) => {
  await ddb.send(new PutCommand({
    TableName: TABLE,
    Item: { pk: event.id, body: event.body, ts: Date.now() },
  }));
  return { statusCode: 200 };
};

// SnapStart: re-initialize anything that must not be shared across restores.
import org.crac.Core;
import org.crac.Resource;
import java.security.SecureRandom;

public class Handler implements Resource {
  private static SecureRandom rng = new SecureRandom();

  public Handler() {
    Core.getGlobalContext().register(this);
  }

  @Override public void beforeCheckpoint(org.crac.Context<? extends Resource> c) {}

  @Override public void afterRestore(org.crac.Context<? extends Resource> c) {
    // Frozen RNG state would otherwise repeat across every restored env.
    rng = new SecureRandom();
    rng.nextLong(); // force reseed from the kernel entropy pool
  }
}

// SQS: report partial batch failures so SQS only retries the failed messages.
// Requires functionResponseTypes: ['ReportBatchItemFailures'] on the ESM.
export const handler = async (event: { Records: { messageId: string; body: string }[] }) => {
  const batchItemFailures: { itemIdentifier: string }[] = [];
  for (const record of event.Records) {
    try {
      await process(record.body);
    } catch (err) {
      // Without this, ONE bad message re-delivers the entire batch.
      batchItemFailures.push({ itemIdentifier: record.messageId });
    }
  }
  return { batchItemFailures };
};

import { DynamoDBClient } from '@aws-sdk/client-dynamodb';
import { DynamoDBDocumentClient, PutCommand, ConditionalCheckFailedException } from '@aws-sdk/lib-dynamodb';

const ddb = DynamoDBDocumentClient.from(new DynamoDBClient({}));

async function claim(idempotencyKey: string): Promise<boolean> {
  try {
    await ddb.send(new PutCommand({
      TableName: process.env.IDEMP_TABLE!,
      Item: { pk: idempotencyKey, status: 'IN_PROGRESS', ttl: Math.floor(Date.now() / 1000) + 86400 },
      ConditionExpression: 'attribute_not_exists(pk)',
    }));
    return true; // we own this work unit
  } catch (e) {
    if (e instanceof ConditionalCheckFailedException) return false; // already claimed
    throw e;
  }
}

// The fix: make the billing side-effect idempotent on objectKey + eTag.
export const handler = async (event: { Records: { s3: { object: { key: string; eTag: string } } }[] }) => {
  for (const r of event.Records) {
    const { key, eTag } = r.Records?.[0] ? r.Records[0].s3.object : r.s3.object;
    const idempotencyKey = `thumb#${key}#${eTag}`;

    await generateThumbnail(key);          // safe to repeat: same output key
    if (await claim(idempotencyKey)) {     // claim succeeds only once per version
      await chargeCustomer(key);           // the side-effect we must not repeat
      await markCompleted(idempotencyKey);
    }
  }
};

