import { S3Client, GetObjectCommand, PutObjectCommand } from '@aws-sdk/client-s3';
import { DynamoDBClient } from '@aws-sdk/client-dynamodb';
import {
  DynamoDBDocumentClient, GetCommand, PutCommand, UpdateCommand,
  ConditionalCheckFailedException,
} from '@aws-sdk/lib-dynamodb';
import sharp from 'sharp';

const s3 = new S3Client({});
const ddb = DynamoDBDocumentClient.from(new DynamoDBClient({}));

const TABLE = process.env.IDEMP_TABLE!;
const THUMB_BUCKET = process.env.THUMB_BUCKET!;
const LEASE_SECONDS = 300; // a crashed claim becomes reclaimable after 5 min

interface S3Event { Records: { s3: { bucket: { name: string }; object: { key: string; eTag: string } } }[] }

async function streamToBuffer(stream: any): Promise<Buffer> {
  const chunks: Buffer[] = [];
  for await (const c of stream) chunks.push(Buffer.from(c));
  return Buffer.concat(chunks);
}

// Returns true if THIS invocation now owns the work and must do the side-effect.
async function tryClaim(key: string): Promise<boolean> {
  const now = Math.floor(Date.now() / 1000);
  try {
    await ddb.send(new PutCommand({
      TableName: TABLE,
      Item: { pk: key, status: 'IN_PROGRESS', leaseExpiry: now + LEASE_SECONDS, ttl: now + 86400 },
      // Claim if no record OR the prior claim is COMPLETED-absent and its lease expired.
      ConditionExpression: 'attribute_not_exists(pk) OR (#s = :inprog AND leaseExpiry < :now)',
      ExpressionAttributeNames: { '#s': 'status' },
      ExpressionAttributeValues: { ':inprog': 'IN_PROGRESS', ':now': now },
    }));
    return true;
  } catch (e) {
    if (e instanceof ConditionalCheckFailedException) return false; // completed or actively in-progress
    throw e;
  }
}

async function markCompleted(key: string): Promise<void> {
  await ddb.send(new UpdateCommand({
    TableName: TABLE,
    Key: { pk: key },
    UpdateExpression: 'SET #s = :done',
    ExpressionAttributeNames: { '#s': 'status' },
    ExpressionAttributeValues: { ':done': 'COMPLETED' },
  }));
}

async function alreadyCompleted(key: string): Promise<boolean> {
  const r = await ddb.send(new GetCommand({ TableName: TABLE, Key: { pk: key } }));
  return r.Item?.status === 'COMPLETED';
}

async function generateThumbnail(bucket: string, key: string): Promise<void> {
  const obj = await s3.send(new GetObjectCommand({ Bucket: bucket, Key: key }));
  const input = await streamToBuffer(obj.Body);
  const thumb = await sharp(input).resize(200, 200, { fit: 'inside' }).jpeg().toBuffer();
  // Idempotent: same output key, safe to repeat.
  await s3.send(new PutObjectCommand({ Bucket: THUMB_BUCKET, Key: `thumbs/${key}.jpg`, Body: thumb, ContentType: 'image/jpeg' }));
}

async function chargeCustomer(key: string): Promise<void> {
  // Non-idempotent side-effect: must run exactly once per object version.
  // (write a billing row, call a payments API, etc.)
}

export const handler = async (event: S3Event) => {
  for (const r of event.Records) {
    const bucket = r.s3.bucket.name;
    const key = decodeURIComponent(r.s3.object.key.replace(/\+/g, ' '));
    const idempotencyKey = `thumb#${key}#${r.s3.object.eTag}`;

    // Fast skip if a prior attempt already completed the billing side-effect.
    if (await alreadyCompleted(idempotencyKey)) continue;

    await generateThumbnail(bucket, key); // safe to repeat regardless of claim

    if (await tryClaim(idempotencyKey)) {
      await chargeCustomer(key);          // guarded: exactly once per version
      await markCompleted(idempotencyKey);
    }
    // else: another invocation owns it (or it's done) -> do not double-charge
  }
};

interface Sample { memoryMB: number; avgDurationMs: number; }
interface Pricing { requestFee: number; gbSecondPrice: number; }
interface Result { memoryMB: number; avgDurationMs: number; costPerMillion: number; }

// us-east-1 x86 on-demand (illustrative): $0.20 per 1M requests, $0.0000166667 per GB-second.
const PRICING: Pricing = { requestFee: 0.20 / 1_000_000, gbSecondPrice: 0.0000166667 };

function costPerMillion(sample: Sample, p: Pricing): number {
  const gbSeconds = (sample.memoryMB / 1024) * (sample.avgDurationMs / 1000);
  const perInvoke = p.requestFee + gbSeconds * p.gbSecondPrice;
  return perInvoke * 1_000_000;
}

function optimalMemory(samples: Sample[], p: Pricing = PRICING): { best: Result; table: Result[] } {
  const table: Result[] = samples.map((s) => ({
    memoryMB: s.memoryMB,
    avgDurationMs: s.avgDurationMs,
    costPerMillion: Number(costPerMillion(s, p).toFixed(4)),
  }));
  const best = table.reduce((a, b) => (b.costPerMillion < a.costPerMillion ? b : a));
  return { best, table };
}

// CPU-bound: duration falls faster than memory rises -> 1769MB beats 512MB on cost.
const measured: Sample[] = [
  { memoryMB: 512, avgDurationMs: 4200 },
  { memoryMB: 1024, avgDurationMs: 2100 },
  { memoryMB: 1769, avgDurationMs: 1180 },
  { memoryMB: 3008, avgDurationMs: 950 },
];

const { best, table } = optimalMemory(measured);
console.table(table);
console.log(`Cheapest: ${best.memoryMB}MB at $${best.costPerMillion} / 1M invocations`);
